package com.example.loginprototype;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class PrefsManager {
    private static final String PREF_NAME = "demo_auth_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";

    private final SharedPreferences sharedPreferences;

    public PrefsManager(Context context) {
        this.sharedPreferences = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }

    public void saveLogin(String email, String authToken) {
        sharedPreferences.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .apply();
    }

    public String getEmail() {
        return sharedPreferences.getString(KEY_EMAIL, null);
    }

    public String getAuthToken() {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null);
    }

    public boolean isLoggedIn() {
        return !TextUtils.isEmpty(getEmail()) && !TextUtils.isEmpty(getAuthToken());
    }

    public void clearLogin() {
        sharedPreferences.edit()
                .remove(KEY_EMAIL)
                .remove(KEY_AUTH_TOKEN)
                .apply();
    }
}

