package com.example.loginprototype;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;

    private PrefsManager prefsManager;
    private AuthRepository authRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        prefsManager = new PrefsManager(this);
        authRepository = new AuthRepository();

        if (prefsManager.isLoggedIn()) {
            openHome();
            return;
        }

        emailInput = findViewById(R.id.etEmail);
        passwordInput = findViewById(R.id.etPassword);
        loginButton = findViewById(R.id.btnLogin);

        String savedEmail = prefsManager.getEmail();
        if (!TextUtils.isEmpty(savedEmail)) {
            emailInput.setText(savedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (TextUtils.isEmpty(email)) {
            emailInput.setError("Enter email");
            emailInput.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Enter password");
            passwordInput.requestFocus();
            return;
        }

        authRepository.login(email, password, new AuthRepository.LoginCallback() {
            @Override
            public void onSuccess(String authToken) {
                prefsManager.saveLogin(email, authToken);
                Toast.makeText(LoginActivity.this, "Login successful", Toast.LENGTH_SHORT).show();
                openHome();
            }

            @Override
            public void onError(String message) {
                Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void openHome() {
        startActivity(new Intent(this, HomeActivity.class));
        finish();
    }
}

package com.example.loginprototype;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView welcomeText;
    private TextView tokenText;
    private Button logoutButton;

    private PrefsManager prefsManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        prefsManager = new PrefsManager(this);

        if (!prefsManager.isLoggedIn()) {
            openLogin();
            return;
        }

        welcomeText = findViewById(R.id.tvWelcome);
        tokenText = findViewById(R.id.tvToken);
        logoutButton = findViewById(R.id.btnLogout);

        welcomeText.setText("Welcome, " + prefsManager.getEmail());
        tokenText.setText("Token: " + prefsManager.getAuthToken());

        logoutButton.setOnClickListener(v -> {
            prefsManager.clearLogin();
            openLogin();
        });
    }

    private void openLogin() {
        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }
}

